import{_ as a,o,c as n,ag as t}from"./chunks/framework.CAXxHpAX.js";const i=JSON.parse('{"title":"唐朝兴盛的原因：政治：国家统一，社会稳定","description":"","frontmatter":{},"headers":[],"relativePath":"notes/note-14.md","filePath":"notes/note-14.md"}'),e={name:"notes/note-14.md"};function r(s,p,l,c,d,b){return o(),n("div",null,[...p[0]||(p[0]=[t('<h1 id="唐朝兴盛的原因-政治-国家统一-社会稳定" tabindex="-1">唐朝兴盛的原因：政治：国家统一，社会稳定 <a class="header-anchor" href="#唐朝兴盛的原因-政治-国家统一-社会稳定" aria-label="Permalink to &quot;唐朝兴盛的原因：政治：国家统一，社会稳定&quot;">​</a></h1><p><span style="color:var(--vp-c-brand-1);font-weight:bold;">唐朝兴盛的原因：</span>政治：国家统一，社会稳定；统治者以民为本，实行有利于生产发展的措施；完善科举制度，重视人才培养；采取开明的民族政策，民族关系相对融洽；开放的对外政策，中外交流频繁；经济：生产力发展（曲辕犁、筒车），经济繁荣；文化：注重文教，文化繁荣。交通：海上陆上丝绸之路，交通发达。</p><p><span style="color:var(--vp-c-brand-1);font-weight:bold;">宋朝兴盛的原因：</span>政治：政府采取重文轻武政策，重视文教事业的发展；中外交流频繁；经济：生产力发展（秧马），经济繁荣；经济重心南移；文化：改革科举制，文化昌盛、人才辈出。交通：海上丝绸之路，交通发达。</p><p><span style="color:var(--vp-c-brand-1);font-weight:bold;">1、闭关锁国原因：</span></p><p>①清朝统治者认为天朝物产丰富，无所不有，不需与外交交流。</p><p>②清朝统治者担心西方殖民者的侵犯和沿海居民同外国人交往，会危及自己的统治。</p><p><span style="color:var(--vp-c-brand-1);font-weight:bold;">2、闭关锁国表现：</span></p><p>①顺治颁布“禁海令”；</p><p>②建台湾府后，开放宁波、漳州等地为通商口岸；</p><p>③1757年，只留广州一处通商口岸，由广州十三行统一经营对外贸易并管理外商。</p><p><span style="color:var(--vp-c-brand-1);font-weight:bold;">3、闭关锁国政策的影响：</span>对西方殖民者的侵略活动，曾起到过一定的自卫作用，但也使中国逐渐落伍于世界历史的发展进程。</p><p><span style="color:var(--vp-c-brand-1);font-weight:bold;">4、长篇章回体小说的开山之作：</span>《三国演义》</p><p><span style="color:var(--vp-c-brand-1);font-weight:bold;">5、浪漫主义色的神话小说：</span>《西游记》</p><p><span style="color:var(--vp-c-brand-1);font-weight:bold;">6、我国古代最优秀的长篇小说：</span>《红楼梦》</p><p><span style="color:var(--vp-c-brand-1);font-weight:bold;">7、戏剧代表：</span>明朝汤显祖《牡丹亭》</p><p><span style="color:var(--vp-c-brand-1);font-weight:bold;">8、清朝的文化专制：</span>文字狱、康熙、雍正和乾隆。</p><p>1、唐朝书法家是？颜真卿、柳公权、欧阳询</p><p><span style="color:var(--vp-c-brand-1);font-weight:bold;">2、明清单元目录：</span>统一多民族国家的巩固和发展</p><p>3、以下哪些发明由阿拉伯人传播到欧洲？B指南针C火药</p><p>A活字印刷术（蒙古人西征）</p><p><span style="color:var(--vp-c-brand-1);font-weight:bold;">4、清朝疆域四至：</span>西跨葱岭，北接西伯利亚 ，东临太平洋，南到南海诸岛。</p><p>5、郑和的船队最远到达哪里？非洲东海岸和红海沿岸</p><p>6、统一蒙古草原的是铁木真（成吉思汗）</p><p><span style="color:var(--vp-c-brand-1);font-weight:bold;">7、中国十七世纪工业百科全书是：</span>《天工开物》 作者是：宋应星（明）</p><p>8、北宋哪里最繁华？开封大相国寺</p><p>9、明朝戏剧家和代表作？汤显祖《牡丹亭》</p><p>1</p><p>0、《农政全书》、农业、徐光启（明）</p><p>1</p><p><span style="color:var(--vp-c-brand-1);font-weight:bold;">1、清朝对新疆地区的管辖措施有？康熙：</span>平定准噶尔叛乱；乾隆：平定大小和卓、设置伊犁将军、哨所、安置土尔扈特部；左宗棠收复新疆，1884年新疆设省。</p>',30)])])}const f=a(e,[["render",r]]);export{i as __pageData,f as default};
